package main

import (
	"fmt"
	"io/ioutil"
	"net/http"
)

// This function handles HTTP GET requests and prints the content of the response.
func printRequestContent(url string) error {
	// Make an HTTP GET request to the specified URL
	resp, err := http.Get(url)
	if err != nil {
		return fmt.Errorf("failed to make HTTP GET request: %w", err)
	}
	defer resp.Body.Close()

	// Check if the request was successful
	if resp.StatusCode != http.StatusOK {
		return fmt.Errorf("failed to get content, status code: %d", resp.StatusCode)
	}

	// Read the response body
	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		return fmt.Errorf("failed to read response body: %w", err)
	}

	// Print the content of the response
	fmt.Printf("Response Content:\n%s\n", body)

	return nil
}

func main() {
	// Example URL
	url := "https://api.example.com/data"
	err := printRequestContent(url)
	if err != nil {
		fmt.Printf("An error occurred: %v\n", err)
	}
}
```

